import{j as i,b as l,c as s,aa as e}from"./chunks/framework.Bxf40uRC.js";const k=JSON.parse('{"title":"Linux常用指令","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/linux常用指令.md","filePath":"Linux/linux常用指令.md","lastUpdated":null}'),t={name:"Linux/linux常用指令.md"},o=e('<h1 id="linux常用指令" tabindex="-1">Linux常用指令 <a class="header-anchor" href="#linux常用指令" aria-label="Permalink to &quot;Linux常用指令&quot;">​</a></h1><h2 id="网络监控" tabindex="-1">网络监控 <a class="header-anchor" href="#网络监控" aria-label="Permalink to &quot;网络监控&quot;">​</a></h2><ol><li><strong>netstat/ss -tunlp</strong> : t 表示tcp，u表示udp，l表示listen，n表示使用ip和端口展示，p展示pid</li><li><strong>iftop</strong>：监控网络带宽的使用情况</li><li><strong>ifconfig</strong>: 查看本地ip地址信息</li></ol><h2 id="系统管理" tabindex="-1">系统管理 <a class="header-anchor" href="#系统管理" aria-label="Permalink to &quot;系统管理&quot;">​</a></h2><ol><li><p><strong>top</strong> ：监控内存和cpu使用率的命令</p><ul><li>过程中按P代表按照CPU使用率降序排序</li><li>M代表按照Memory降序排序</li><li>按下1显示所有cpu的核心使用情况</li></ul></li><li><p><strong>free</strong>：命令用于显示系统的空闲、已用、交换空间等内存信息</p><ul><li><code>-b</code>：以字节为单位显示内存使用情况。</li><li><code>-k</code>：以KB为单位显示内存使用情况（这是默认设置）。</li><li><code>-m</code>：以MB为单位显示内存使用情况。</li><li><code>-g</code>：以GB为单位显示内存使用情况。</li><li><code>-h</code>：以人类可读的格式（自动选择适当的单位，例如KB、MB或GB）显示内存使用情况。</li><li><code>-t</code>：显示内存总计行（即总计物理内存+交换空间）。</li></ul></li><li><p><code>vmstat</code>（Virtual Memory Statistics）命令是Linux系统中用于显示关于虚拟内存、进程、CPU活动等信息的工具。它提供了系统的即时状态，包括内存使用、系统进程、中断、CPU活动和交换空间使用情况。<code>vmstat</code>可以帮助识别系统的性能瓶颈，特别是内存和CPU相关的问题。</p><ul><li>Procs（进程） <ul><li><code>r</code>：等待运行的进程数。</li><li><code>b</code>：处于不可中断睡眠状态的进程数。</li></ul></li><li>Memory（内存） <ul><li><code>swpd</code>：使用的交换空间大小。</li><li><code>free</code>：空闲的物理内存大小。</li><li><code>buff</code>：用作缓冲的内存大小。</li><li><code>cache</code>：用作缓存的内存大小。</li></ul></li><li>Swap（交换） <ul><li><code>si</code>：每秒从交换空间读入内存的数据量。</li><li><code>so</code>：每秒从内存写入交换空间的数据量。</li></ul></li><li>IO（输入/输出） <ul><li><code>bi</code>：每秒从块设备读入的数据量。</li><li><code>bo</code>：每秒向块设备写入的数据量。</li></ul></li><li>System（系统） <ul><li><code>in</code>：每秒的中断次数，包括时钟中断。</li><li><code>cs</code>：每秒的上下文切换次数。</li></ul></li><li>CPU（中央处理器） <ul><li><code>us</code>：用户模式下CPU的时间百分比。</li><li><code>sy</code>：系统（内核）模式下CPU的时间百分比。</li><li><code>id</code>：空闲CPU的时间百分比。</li><li><code>wa</code>：等待IO的CPU时间百分比。</li><li><code>st</code>：被偷走的时间百分比（对于虚拟机环境）。</li></ul></li><li>cat /proc/vmstat | grep &#39;pswpin|pswpout&#39; ：可以用来统计内存交换的次数</li></ul></li><li><p><strong>systemctl</strong>：控制systemd系统和服务管理器。</p><ul><li><p>启动服务：<code>systemctl start servicename</code></p></li><li><p>停止服务：<code>systemctl stop servicename</code></p></li><li><p>重启服务：<code>systemctl restart servicename</code></p></li><li><p>显示服务状态：<code>systemctl status servicename</code></p></li><li><p>开机自启：<code>systemctl enable servicename</code></p></li><li><p>禁止开机自启：<code>systemctl disable servicename</code></p></li></ul></li><li><p><strong>ps</strong>：显示当前所有的进程</p><ul><li>-e显示所有进程</li><li>-f表示全格式</li><li>a表示显示除控制进程（session leaders）和没有控制终端的进程外的所有进程</li><li>u表示用户为中心的格式输出，提供每个进程的用户名称，CPU和内存使用率等详细信息</li><li>x显示没有控制终端的进程，通常与进行一起使用</li></ul></li><li><p><strong>kill -9 pid</strong>: -9强制终止进程，不加的话就是终止进程</p></li><li><p><strong>killall</strong>：根据进程名终止所有进程</p></li><li><p><strong>jobs</strong>：列出当前会话中的所有任务，包括后台运行的进程。</p></li><li><p><strong>nice</strong>：优先级范围从-20（最高优先级）到19（最低优先级)</p><ul><li>nice -n 5 command：表示nice值 + 5启动command，通常越小，优先级越高</li></ul></li><li><p><strong>journalctl</strong> : 查看系统所有日志</p></li></ol><ul><li>-u 表示查看特定服务的日志</li><li>--since today 表示查看今天的日志</li><li>-f 滚动查看最新的日志</li><li>--since &quot;2021-01-30 14:00&quot; --until &quot;2021-01-30 16:00&quot; 查看某个时间段的日志</li></ul><ol start="11"><li><strong>lscpu</strong>：查看cpu信息</li><li><strong>getconf</strong>：可以获取系统变量的值 <ul><li>LONG_BIT：表示长整型的bit数目</li></ul></li><li><strong>df</strong>：显示文件系统的磁盘空间信息 <ul><li>-h：人类可读；</li><li>-a：显示所有文件系统的详细信息，包括特殊文件系统；</li><li>-l：仅显示本地文件系统，不包括通过网络挂载的文件系统；</li><li>-i：显示文件系统的inode的使用情况，包括已用inode数量、剩余inode数量以及inode使用率；</li></ul></li></ol><h2 id="文件操作" tabindex="-1">文件操作 <a class="header-anchor" href="#文件操作" aria-label="Permalink to &quot;文件操作&quot;">​</a></h2><ol><li><p><strong>pwd</strong>：显示当前文件目录</p></li><li><p><strong>mv</strong>： 可以进行文件命名操作，也可以进行文件移动操作</p></li><li><p><strong>ls</strong>：显示文件或者文件夹的信息</p><ul><li>-a 显示所有文件和目录，包括以.开头的</li><li>-l 以详细格式列出文件和目录的信息，权限、链接数、所有者、组、大小、时间戳、名称</li><li>-d 显示文件夹本身，而不是它们包含的信息</li><li>-h (human readable)人类更容易阅读的方式</li></ul></li><li><p><strong>tr</strong> 命令的一般语法如下：</p><ul><li>tr [选项]... SET1 [SET2] 代表将set1中的字符转成set2中的字符 <ul><li>-d 表示删除set1中存在的字符，<strong>一般不能够用来删除汉字，因为汉字字节数不是1</strong></li><li>-s 压缩set1中连续存在的字符，中文不行，底层应该是utf-8，所以导致汉字的编码不是一个字节</li><li>-c 表示求补集，通常用来删除，不在set1中的字符</li></ul></li></ul></li><li><p><strong>uniq</strong> 用来删除相邻的重复项</p><ul><li>-c统计字符频率</li></ul></li><li><p><strong>sort</strong>：对字符进行排序操作，一般是字典序</p><ul><li>-c：反向排序；</li></ul></li><li><p><strong>tail</strong>：反向输出文件</p><ul><li>-n + x 表示从第几行开始输出；</li><li>tail -n x 表示查看后面x行的日志；</li></ul></li><li><p><strong>head</strong>：查看文件开头</p><ul><li>-n x 表示查看开头x行；</li><li>-n -x 表示查看除了最后x行的日志；</li></ul></li><li><p><strong>find</strong>：find [路径][表达式]是一个强大的用于在Linux和Unix系统中查找文件和目录的命令行工具</p><ul><li>-name：按照文件名匹配查找</li><li>-type：根据文件类型匹配查找，如文件(&#39;f&#39;)、目录(&#39;d&#39;)等；</li><li>-size：根据文件大小匹配查找</li><li>-mtime、-atime、-ctime：根据文件修改时间、访问时间、状态改变时间匹配查找；</li><li>-exec：对查找到的文件执行指定的命令；</li></ul><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> f</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mtime</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -30</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -size</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +1M</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> {}</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\;</span></span></code></pre></div></li><li><p><strong>grep</strong>：文件搜索命令</p></li></ol><ul><li><code>-i</code>：忽略大小写。</li><li><code>-v</code>：显示不匹配的行。</li><li><code>-n</code>：显示匹配行的行号。</li><li><code>-r</code> 或 <code>--recursive</code>：递归搜索子目录。</li><li><code>-A num</code>：显示匹配行后的 num 行上下文。</li><li><code>-B num</code>：显示匹配行前的 num 行上下文。</li><li><code>-C num</code>：显示匹配行前后的 num 行上下文。</li><li><strong>-o</strong>：仅输出匹配到的部分，<strong>-E</strong>：启用扩展的正则表达式</li></ul><ol start="11"><li><p><strong>sed</strong>：这个命令可以查找日志文件特定的一段 , 根据时间的一个范围查询，可以按照行号和时间范围查询</p><ul><li>按照行号</li></ul><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sed </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;5,10p&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> filename 这样你就可以只查看文件的第5行到第10行。</span></span></code></pre></div><ul><li>按照时间段</li></ul><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sed </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;/2014-12-17 16:17:20/,/2014-12-17 16:17:36/p&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  test.log</span></span></code></pre></div></li><li><p><strong>less</strong>：查找文件内容</p><ul><li>shift + G 命令到文件尾部</li><li>？可以查询你想要查询的关键字</li><li>n向上查找关键字</li><li>shift + n反向查找关键字</li></ul></li><li><p><strong>echo</strong>：用于在终端命令行中输出文本内容或者变量的值</p><ul><li>echo [options] [string]</li><li>-n: 禁止在输出末尾添加换行符；</li><li>-e: 启用解释转移字符，可以将转义序列解释为特殊字符(如\\n表示换行符)；</li><li>-E: 禁止解释转义字符，将转义字符原样输出；</li></ul></li></ol>',11),n=[o];function a(p,c,d,r,h,u){return l(),s("div",null,n)}const m=i(t,[["render",a]]);export{k as __pageData,m as default};
